[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/complete-dataset-001> ;
            sh:resultMessage "Activity contains instrument objects (schema:instrument); this suggests cdifProv-level provenance. Consider declaring conformance to CDIFcomplete or a domain-specific profile." ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraint [ a sh:SPARQLConstraint ;
                    sh:message "Activity contains instrument objects (schema:instrument); this suggests cdifProv-level provenance. Consider declaring conformance to CDIFcomplete or a domain-specific profile." ;
                    sh:prefixes ( [ sh:namespace "http://schema.org/" ;
                                sh:prefix "schema" ] [ sh:namespace "http://www.w3.org/ns/prov#" ;
                                sh:prefix "prov" ] ) ;
                    sh:select """
			PREFIX schema: <http://schema.org/>
			PREFIX prov: <http://www.w3.org/ns/prov#>
			SELECT $this WHERE {
				$this prov:wasGeneratedBy ?activity .
				?activity prov:used ?usedItem .
				?usedItem schema:instrument ?inst .
			}
		""" ;
                    sh:severity sh:Warning ] ;
            sh:sourceConstraintComponent sh:SPARQLConstraintComponent ;
            sh:sourceShape cdifd:cdifOptionalProvWarningShape ;
            sh:value <https://example.org/complete-dataset-001> ] .

